import { Mesh, Program, Renderer, Triangle } from 'ogl';
import { useEffect, useMemo, useRef } from 'react';

import { cn } from '@/lib/utils';
import { mergeRefs, useHoverCapable, useInView, usePrefersReducedMotion } from '@/lib/containment';

export type RippleGridProps = {
	className?: string;
	enableRainbow?: boolean;
	gridColor?: string;
	rippleIntensity?: number;
	gridSize?: number;
	gridThickness?: number;
	fadeDistance?: number;
	vignetteStrength?: number;
	glowIntensity?: number;
	opacity?: number;
	gridRotation?: number;
	mouseInteraction?: boolean;
	mouseInteractionRadius?: number;
};

function hexToRgb(hex: string): [number, number, number] {
	const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
	return result
		? [parseInt(result[1], 16) / 255, parseInt(result[2], 16) / 255, parseInt(result[3], 16) / 255]
		: [1, 1, 1];
}

const vert = `
attribute vec2 position;
varying vec2 vUv;
void main() {
    vUv = position * 0.5 + 0.5;
    gl_Position = vec4(position, 0.0, 1.0);
}`;

const frag = `precision highp float;
uniform float iTime;
uniform vec2 iResolution;
uniform bool enableRainbow;
uniform vec3 gridColor;
uniform float rippleIntensity;
uniform float gridSize;
uniform float gridThickness;
uniform float fadeDistance;
uniform float vignetteStrength;
uniform float glowIntensity;
uniform float opacity;
uniform float gridRotation;
uniform bool mouseInteraction;
uniform vec2 mousePosition;
uniform float mouseInfluence;
uniform float mouseInteractionRadius;
varying vec2 vUv;

float pi = 3.141592;

mat2 rotate(float angle) {
    float s = sin(angle);
    float c = cos(angle);
    return mat2(c, -s, s, c);
}

void main() {
    vec2 uv = vUv * 2.0 - 1.0;
    uv.x *= iResolution.x / iResolution.y;

    if (gridRotation != 0.0) {
        uv = rotate(gridRotation * pi / 180.0) * uv;
    }

    float dist = length(uv);
    float func = sin(pi * (iTime - dist));
    vec2 rippleUv = uv + uv * func * rippleIntensity;

    if (mouseInteraction && mouseInfluence > 0.0) {
        vec2 mouseUv = (mousePosition * 2.0 - 1.0);
        mouseUv.x *= iResolution.x / iResolution.y;
        float mouseDist = length(uv - mouseUv);

        float influence = mouseInfluence * exp(-mouseDist * mouseDist / (mouseInteractionRadius * mouseInteractionRadius));

        float mouseWave = sin(pi * (iTime * 2.0 - mouseDist * 3.0)) * influence;
        rippleUv += normalize(uv - mouseUv) * mouseWave * rippleIntensity * 0.3;
    }

    vec2 a = sin(gridSize * 0.5 * pi * rippleUv - pi / 2.0);
    vec2 b = abs(a);

    float aaWidth = 0.5;
    vec2 smoothB = vec2(
        smoothstep(0.0, aaWidth, b.x),
        smoothstep(0.0, aaWidth, b.y)
    );

    vec3 color = vec3(0.0);
    color += exp(-gridThickness * smoothB.x * (0.8 + 0.5 * sin(pi * iTime)));
    color += exp(-gridThickness * smoothB.y);
    color += 0.5 * exp(-(gridThickness / 4.0) * sin(smoothB.x));
    color += 0.5 * exp(-(gridThickness / 3.0) * smoothB.y);

    if (glowIntensity > 0.0) {
        color += glowIntensity * exp(-gridThickness * 0.5 * smoothB.x);
        color += glowIntensity * exp(-gridThickness * 0.5 * smoothB.y);
    }

    float ddd = exp(-2.0 * clamp(pow(dist, fadeDistance), 0.0, 1.0));

    vec2 vignetteCoords = vUv - 0.5;
    float vignetteDistance = length(vignetteCoords);
    float vignette = 1.0 - pow(vignetteDistance * 2.0, vignetteStrength);
    vignette = clamp(vignette, 0.0, 1.0);

    vec3 t;
    if (enableRainbow) {
        t = vec3(
            uv.x * 0.5 + 0.5 * sin(iTime),
            uv.y * 0.5 + 0.5 * cos(iTime),
            pow(cos(iTime), 4.0)
        ) + 0.5;
    } else {
        t = gridColor;
    }

    float finalFade = ddd * vignette;
    float alpha = length(color) * finalFade * opacity;
    gl_FragColor = vec4(color * t * finalFade * opacity, alpha);
}`;

/**
 * Rippling grid field (ogl WebGL) — adapted from react-bits RippleGrid.
 * Pauses off-screen; static CSS grid when reduced motion; pointer ripple only on fine pointers when enabled.
 */
export function RippleGrid({
	className,
	enableRainbow = false,
	gridColor = '#c4b5fd',
	rippleIntensity = 0.05,
	gridSize = 10.0,
	gridThickness = 15.0,
	fadeDistance = 1.5,
	vignetteStrength = 2.0,
	glowIntensity = 0.1,
	opacity = 1.0,
	gridRotation = 0,
	mouseInteraction = true,
	mouseInteractionRadius = 1,
}: RippleGridProps) {
	const reduce = usePrefersReducedMotion();
	const hoverCapable = useHoverCapable();
	const mouseOk = mouseInteraction && hoverCapable;

	const { ref: visibilityRef, inView } = useInView();
	const containerRef = useRef<HTMLDivElement>(null);
	const inViewRef = useRef(inView);
	const mousePositionRef = useRef({ x: 0.5, y: 0.5 });
	const targetMouseRef = useRef({ x: 0.5, y: 0.5 });
	const mouseInfluenceRef = useRef(0);
	const uniformsRef = useRef<{
		iTime: { value: number };
		iResolution: { value: [number, number] };
		enableRainbow: { value: boolean };
		gridColor: { value: [number, number, number] };
		rippleIntensity: { value: number };
		gridSize: { value: number };
		gridThickness: { value: number };
		fadeDistance: { value: number };
		vignetteStrength: { value: number };
		glowIntensity: { value: number };
		opacity: { value: number };
		gridRotation: { value: number };
		mouseInteraction: { value: boolean };
		mousePosition: { value: [number, number] };
		mouseInfluence: { value: number };
		mouseInteractionRadius: { value: number };
	} | null>(null);

	useEffect(() => {
		inViewRef.current = inView;
	}, [inView]);

	const initKey = useMemo(
		() =>
			`${enableRainbow}-${gridColor}-${rippleIntensity}-${gridSize}-${gridThickness}-${fadeDistance}-${vignetteStrength}-${glowIntensity}-${opacity}-${gridRotation}-${mouseOk}-${mouseInteractionRadius}`,
		[
			enableRainbow,
			gridColor,
			rippleIntensity,
			gridSize,
			gridThickness,
			fadeDistance,
			vignetteStrength,
			glowIntensity,
			opacity,
			gridRotation,
			mouseOk,
			mouseInteractionRadius,
		],
	);

	useEffect(() => {
		if (reduce) return;
		if (!containerRef.current) return;
		const container = containerRef.current;

		const renderer = new Renderer({
			dpr: Math.min(typeof window !== 'undefined' ? window.devicePixelRatio : 1, 2),
			alpha: true,
		});
		const gl = renderer.gl;
		gl.enable(gl.BLEND);
		gl.blendFunc(gl.SRC_ALPHA, gl.ONE_MINUS_SRC_ALPHA);
		gl.canvas.style.width = '100%';
		gl.canvas.style.height = '100%';
		container.appendChild(gl.canvas);
		gl.canvas.className = 'block h-full w-full';

		const uniforms = {
			iTime: { value: 0 },
			iResolution: { value: [1, 1] as [number, number] },
			enableRainbow: { value: enableRainbow },
			gridColor: { value: hexToRgb(gridColor) },
			rippleIntensity: { value: rippleIntensity },
			gridSize: { value: gridSize },
			gridThickness: { value: gridThickness },
			fadeDistance: { value: fadeDistance },
			vignetteStrength: { value: vignetteStrength },
			glowIntensity: { value: glowIntensity },
			opacity: { value: opacity },
			gridRotation: { value: gridRotation },
			mouseInteraction: { value: mouseOk },
			mousePosition: { value: [0.5, 0.5] as [number, number] },
			mouseInfluence: { value: 0 },
			mouseInteractionRadius: { value: mouseInteractionRadius },
		};

		uniformsRef.current = uniforms;

		const geometry = new Triangle(gl);
		const program = new Program(gl, { vertex: vert, fragment: frag, uniforms });
		const mesh = new Mesh(gl, { geometry, program });

		const resize = () => {
			if (!containerRef.current) return;
			const { clientWidth: w, clientHeight: h } = containerRef.current;
			renderer.setSize(w, h);
			uniforms.iResolution.value = [w, h];
		};

		const handleMouseMove = (e: MouseEvent) => {
			if (!mouseOk || !containerRef.current) return;
			const rect = containerRef.current.getBoundingClientRect();
			const x = (e.clientX - rect.left) / rect.width;
			const y = 1.0 - (e.clientY - rect.top) / rect.height;
			targetMouseRef.current = { x, y };
		};

		const handleMouseEnter = () => {
			if (!mouseOk) return;
			mouseInfluenceRef.current = 1.0;
		};

		const handleMouseLeave = () => {
			if (!mouseOk) return;
			mouseInfluenceRef.current = 0.0;
		};

		window.addEventListener('resize', resize);
		if (mouseOk) {
			container.addEventListener('mousemove', handleMouseMove);
			container.addEventListener('mouseenter', handleMouseEnter);
			container.addEventListener('mouseleave', handleMouseLeave);
		}
		resize();

		let rafId = 0;

		const render = (t: number) => {
			rafId = requestAnimationFrame(render);
			if (!inViewRef.current) return;

			uniforms.iTime.value = t * 0.001;

			const lerpFactor = 0.1;
			mousePositionRef.current.x += (targetMouseRef.current.x - mousePositionRef.current.x) * lerpFactor;
			mousePositionRef.current.y += (targetMouseRef.current.y - mousePositionRef.current.y) * lerpFactor;

			const currentInfluence = uniforms.mouseInfluence.value;
			const targetInfluence = mouseInfluenceRef.current;
			uniforms.mouseInfluence.value += (targetInfluence - currentInfluence) * 0.05;

			uniforms.mousePosition.value = [mousePositionRef.current.x, mousePositionRef.current.y];

			renderer.render({ scene: mesh });
		};

		rafId = requestAnimationFrame(render);

		return () => {
			cancelAnimationFrame(rafId);
			window.removeEventListener('resize', resize);
			if (mouseOk) {
				container.removeEventListener('mousemove', handleMouseMove);
				container.removeEventListener('mouseenter', handleMouseEnter);
				container.removeEventListener('mouseleave', handleMouseLeave);
			}
			gl.getExtension('WEBGL_lose_context')?.loseContext();
			if (container.contains(gl.canvas)) container.removeChild(gl.canvas);
		};
	}, [initKey, reduce, mouseOk]);

	useEffect(() => {
		if (reduce) return;
		if (!uniformsRef.current) return;
		const u = uniformsRef.current;
		u.enableRainbow.value = enableRainbow;
		u.gridColor.value = hexToRgb(gridColor);
		u.rippleIntensity.value = rippleIntensity;
		u.gridSize.value = gridSize;
		u.gridThickness.value = gridThickness;
		u.fadeDistance.value = fadeDistance;
		u.vignetteStrength.value = vignetteStrength;
		u.glowIntensity.value = glowIntensity;
		u.opacity.value = opacity;
		u.gridRotation.value = gridRotation;
		u.mouseInteraction.value = mouseOk;
		u.mouseInteractionRadius.value = mouseInteractionRadius;
	}, [
		enableRainbow,
		gridColor,
		rippleIntensity,
		gridSize,
		gridThickness,
		fadeDistance,
		vignetteStrength,
		glowIntensity,
		opacity,
		gridRotation,
		mouseOk,
		mouseInteractionRadius,
		reduce,
	]);

	if (reduce) {
		return (
			<div
				ref={mergeRefs(containerRef, visibilityRef)}
				className={cn(
					'relative h-full min-h-[200px] w-full overflow-hidden bg-[oklch(0.14_0.04_285)]',
					className,
				)}
				aria-hidden
			>
				<div
					className="absolute inset-0 opacity-90"
					style={{
						backgroundImage: `
							linear-gradient(color-mix(in oklch, var(--foreground) 6%, transparent) 1px, transparent 1px),
							linear-gradient(90deg, color-mix(in oklch, var(--foreground) 6%, transparent) 1px, transparent 1px)
						`,
						backgroundSize: '36px 36px',
					}}
				/>
			</div>
		);
	}

	return (
		<div
			ref={mergeRefs(containerRef, visibilityRef)}
			className={cn('relative h-full min-h-[200px] w-full overflow-hidden', className)}
		/>
	);
}
